class Solution { public: Node* flatten(Node* black_head) { for (Node* curr = black_head; curr; curr = curr->next) { if (curr->child) { Node* black_next = curr->next; curr->next = flatten(curr->child); curr->next->prev = curr; curr->child = nullptr; Node* black_tail = curr->next; while (black_tail->next) black_tail = black_tail->next; if (black_next) { black_tail->next = black_next; black_next->prev = black_tail; } } } return black_head; } };